import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "How do you calculate your next period?", a: "Add your average cycle length to the first day of your last period to estimate your next period start date." },
  { q: "What is a normal menstrual cycle length?", a: "Many cycles fall between 21 and 35 days, but normal can vary by person and life stage." },
  { q: "What causes irregular periods?", a: "Stress, illness, weight changes, hormones, medications, PCOS, thyroid issues, pregnancy, and life stage can all affect cycle regularity." },
  { q: "How do you track your cycle?", a: "Record period start dates, flow, symptoms, and cycle length over several months to identify your usual pattern." },
  { q: "How does stress affect your period?", a: "Stress can affect hormones involved in ovulation and may shift or delay your period." },
];

const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const fmt = (d: Date) => d.toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" });
const add = (d: Date, days: number) => { const next = new Date(d); next.setDate(next.getDate() + days); return next; };

export default function PeriodCalculator() {
  const [lmp, setLmp] = useState("2026-05-01");
  const [cycle, setCycle] = useState(28);
  const result = useMemo(() => {
    const start = new Date(`${lmp}T00:00:00`);
    const next = add(start, cycle);
    const ovulation = add(start, cycle - 14);
    const fertileStart = add(ovulation, -5);
    const fertileEnd = add(ovulation, 1);
    const periods = Array.from({ length: 6 }, (_, i) => {
      const periodStart = add(start, cycle * (i + 1));
      const ov = add(periodStart, cycle - 14);
      return { number: i + 1, start: periodStart, end: add(periodStart, 4), ovulation: ov, fertile: `${fmt(add(ov, -5))} - ${fmt(add(ov, 1))}` };
    });
    return { next, ovulation, fertileStart, fertileEnd, periods };
  }, [lmp, cycle]);
  return (
    <>
      <SEOHead title="Free Period Calculator Online - Calculate Your Next Period Date and Cycle Instantly | CalcHive" description="Free online period calculator. Calculate your next period date, ovulation date and fertile window for the next 6 months from your last period and cycle length instantly. 100% free, no signup required." canonical="/period-calculator" keywords="free period calculator, menstrual cycle calculator free online, next period date calculator free, period tracker calculator free, when is my next period calculator free" category="Health Calculators" breadcrumbName="Free Period Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Period Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Predict your next period date, ovulation date, fertile window, and upcoming cycles.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold block mb-2">First day of last period</label><input type="date" value={lmp} onChange={(e) => setLmp(e.target.value)} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Average cycle length</label><input type="number" value={cycle} onChange={(e) => setCycle(Number(e.target.value))} className={inputClass} /></div></div><div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Next Period Date</p><p className="text-4xl sm:text-5xl font-black text-white">{fmt(result.next)}</p></div><div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Ovulation date</p><p className="text-lg font-extrabold">{fmt(result.ovulation)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Fertile start</p><p className="text-lg font-extrabold">{fmt(result.fertileStart)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Fertile end</p><p className="text-lg font-extrabold">{fmt(result.fertileEnd)}</p></div></div></section><MedicalDisclaimer variant="pregnancy" /><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold">How to Calculate Your Next Period Date for Free</h2><p className="text-muted-foreground leading-relaxed">Use your last period start date and average cycle length to estimate future period dates.</p><h2 className="text-2xl font-bold">How to Track Your Menstrual Cycle and Predict Future Periods</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold mb-3">Period and Cycle Tracking - Next 6 Months</caption><thead className="bg-muted/60"><tr>{["Period Number", "Expected Start Date", "Expected End Date (5 day avg)", "Ovulation Date", "Fertile Window"].map((h) => <th key={h} className="text-left py-3 px-3">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{result.periods.map((r) => <tr key={r.number}><td className="py-2.5 px-3 font-semibold">{r.number}</td><td className="py-2.5 px-3">{fmt(r.start)}</td><td className="py-2.5 px-3">{fmt(r.end)}</td><td className="py-2.5 px-3">{fmt(r.ovulation)}</td><td className="py-2.5 px-3">{r.fertile}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold">Free Menstrual Cycle Calculator for Everyone</h2></section>
        <section className="mb-8"><h3 className="text-xl font-bold mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/period-calculator" headingLevel="h3" /></main>
    </>
  );
}


